<?php
namespace Tests\Feature;
use App\Domain\Inventory\ItemClassification;use App\Domain\Loot\LootConfigurationValidator;use App\Models\Item;use App\Models\Monster;use App\Models\MonsterLootEntry;use Database\Seeders\WorldCatalogSeeder;use Illuminate\Foundation\Testing\RefreshDatabase;use Tests\TestCase;
class LootConfigurationValidatorTest extends TestCase{use RefreshDatabase;public function test_validation_update_and_duplicate_rules(){$this->seed(WorldCatalogSeeder::class);$m=Monster::where('code','grey_wolf')->first();$i=Item::where('code','worn_leather')->first();$e=MonsterLootEntry::where('monster_id',$m->id)->where('item_id',$i->id)->first();$v=new LootConfigurationValidator(app(ItemClassification::class));$v->validate($m,$i,7000,1,3,'active',$e);foreach([[0,1,1,'active'],[10001,1,1,'active'],[1,0,1,'active'],[1,2,1,'active'],[1,1,1,'bad']] as $x){try{$v->validate($m,$i,$x[0],$x[1],$x[2],$x[3],$e);$this->fail();}catch(\InvalidArgumentException $exception){$this->assertTrue(true);}}$this->expectException(\InvalidArgumentException::class);$v->validate($m,$i,7000,1,3,'active');}public function test_inactive_and_hidden_catalogs_can_be_configured(){$this->seed(WorldCatalogSeeder::class);$m=Monster::where('code','young_boar')->first();$i=Item::where('code','wolf_fang')->first();$m->status='inactive';$m->save();$i->status='hidden';$i->save();(new LootConfigurationValidator(app(ItemClassification::class)))->validate($m,$i,1,1,1,'hidden');$this->assertTrue(true);}}
